/**
 * Docs sidebar.
 *
 * The Guides, Tutorials, and API Reference sub-trees stay AUTOGENERATED from
 * their folders (`dirName`), so new pages there surface with no edit here.
 *
 * The ESPN Reference section is instead an EXPLICIT, sport-grouped category
 * built by codegen: `docs/src/generated/reference-sidebar.js` nests every
 * league reference doc under a collapsible category named for its sport (and
 * the provider namespaces under "Providers"). That file is regenerated by
 * `npm run codegen` from `tools/codegen/endpoints/leagues.yaml`, so a new
 * league/provider auto-lands in the right group — no manual sidebar edit.
 *
 * A Playground link sits near the top so the live REPL is reachable while
 * browsing the docs.
 */
const referenceSidebar = require('./src/generated/reference-sidebar.js');

module.exports = {
  docs: [
    { type: 'doc', id: 'intro', label: 'Getting Started' },
    { type: 'link', label: '🛝 Playground', href: '/playground' },
    { type: 'autogenerated', dirName: 'guides' },
    { type: 'autogenerated', dirName: 'tutorials' },
    {
      type: 'category',
      label: 'ESPN Reference',
      collapsible: true,
      collapsed: true,
      // Generated, grouped-by-sport reference tree (drift-guarded by codegen).
      items: referenceSidebar,
    },
    { type: 'autogenerated', dirName: 'api' },
  ],
};
